mapper.select:
SELECT o.order_status as status, o.create_time, o.time_slot, o.schedule_date AS appointment_date, u.real_name AS patient_name, u.phone AS patient_phone, dep.name AS department_name FROM appoint_order o LEFT JOIN user u ON o.patient_id = u.id LEFT JOIN doctor d ON o.doctor_id = d.id LEFT JOIN depart dep ON o.depart_id = dep.id
o.doctor_id = #{id}
AND o.order_status = #{status}
AND o.schedule_data = #{time}
AND ( u.real_name LIKE CONCAT('%', #{keyword}, '%') OR u.phone LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY o.create_time DESC
